// SPDX-License-Identifier: ISC
//! Replay of frozen netsync vectors generated by an in-package dump
//! test running inside dcrd's internal/netsync package at
//! release-v2.1.5: a scripted 87-step scenario driving a real
//! `SyncManager` wired to a real chain (fed with dcrd's own
//! fullblocktests blocks), real peers over synchronous pipes whose
//! received messages were recorded byte for byte, and a real
//! mempool/mixpool.  The replay drives the ported manager over the
//! REAL Rust chain engine with scripted transaction/mixing pools
//! (both pools are pinned by their own pieces), comparing every
//! queued message, disconnect, request map, and sync state probe.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use std::collections::{BTreeMap, HashMap, HashSet};

use dcroxide_blockchain::RuleErrorKind;
use dcroxide_blockchain::process::Chain;
use dcroxide_chaincfg::{Params, mainnet_params, regnet_params};
use dcroxide_chainhash::Hash;
use dcroxide_containers::apbf;
use dcroxide_netsync::{
    Action, BestSnapshot, Config, Peer, ProcessBlockFailure, SyncChain, SyncManager, SyncMixPool,
    SyncTxPool,
};
use dcroxide_wire::{
    BlockHeader, InvType, InvVect, MsgBlock, MsgHeaders, MsgInv, MsgNotFound, MsgTx,
    PROTOCOL_VERSION, ServiceFlag,
};

const VECTORS: &str = include_str!("data/netsync_vectors.txt");

fn empty_header() -> BlockHeader {
    let (header, _) = BlockHeader::from_bytes(&[0u8; 180]).expect("zero header");
    header
}

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

/// The real chain engine behind the manager's chain trait, using the
/// pinned dump wall clock.
struct ChainAdapter {
    chain: Chain,
    params: Params,
    now: i64,
}

impl ChainAdapter {
    fn tip(&self) -> dcroxide_blockchain::blockindex::NodeId {
        self.chain.best_chain.tip().expect("tip")
    }
}

impl SyncChain for ChainAdapter {
    fn best_header(&mut self) -> (Hash, i64) {
        let Some(best) = self.chain.index.best_header() else {
            return (Hash([0u8; 32]), 0);
        };
        let node = self.chain.store.node(best);
        (node.hash, node.height)
    }

    fn header_by_hash(&mut self, hash: &Hash) -> Option<BlockHeader> {
        self.chain.header_by_hash(hash)
    }

    fn block_locator_from_hash(&mut self, hash: &Hash) -> Vec<Hash> {
        self.chain.block_locator_from_hash(hash)
    }

    fn put_next_needed_blocks(&mut self, max_results: usize) -> Vec<Hash> {
        self.chain.put_next_needed_blocks(max_results)
    }

    fn best_snapshot(&mut self) -> BestSnapshot {
        let snap = &self.chain.state_snapshot;
        BestSnapshot {
            hash: snap.hash,
            height: snap.height,
            next_stake_diff: snap.next_stake_diff,
        }
    }

    fn is_current(&mut self) -> bool {
        let tip = self.tip();
        self.chain.is_current(tip, self.now)
    }

    fn maybe_update_is_current(&mut self) {
        let tip = self.tip();
        self.chain.maybe_update_is_current(tip, self.now);
    }

    fn chain_work(&mut self, hash: &Hash) -> Option<dcroxide_uint256::Uint256> {
        self.chain.chain_work(hash)
    }

    fn have_header(&mut self, hash: &Hash) -> bool {
        self.chain.index.lookup_node(hash).is_some()
    }

    fn have_block(&mut self, hash: &Hash) -> bool {
        self.chain.index.lookup_node(hash).is_some_and(|n| {
            self.chain
                .index
                .node_status(&self.chain.store, n)
                .have_data()
        })
    }

    fn process_block_header(&mut self, header: &BlockHeader) -> Result<(), String> {
        let now = self.now;
        let params = self.params.clone();
        self.chain
            .process_block_header(header, now, &params)
            .map_err(|e| format!("{:?}", e.kind))
    }

    fn process_block(&mut self, block: &MsgBlock) -> Result<i64, ProcessBlockFailure> {
        let now = self.now;
        let params = self.params.clone();
        let (fork_len, errs) = self.chain.process_block(block, now, &params);
        if errs.is_empty() {
            return Ok(fork_len);
        }
        Err(ProcessBlockFailure {
            is_duplicate_block: errs[0].kind == RuleErrorKind::DuplicateBlock,
            message: errs[0].description.clone(),
        })
    }
}

/// A scripted transaction pool mirroring what dcrd's real mempool
/// returned during the dump: the crafted orphan transaction is
/// accepted as an orphan (empty accepted list, tracked afterwards)
/// and the crafted invalid transaction is rejected.
#[derive(Default)]
struct ScriptedTxPool {
    orphan_hash: Hash,
    bad_hash: Hash,
    have: HashSet<Hash>,
}

impl SyncTxPool for ScriptedTxPool {
    fn process_transaction(
        &mut self,
        tx: &MsgTx,
        _allow_orphan: bool,
        _allow_high_fees: bool,
        _tag: u64,
    ) -> Result<Vec<Hash>, String> {
        let hash = tx.tx_hash();
        if hash == self.orphan_hash {
            self.have.insert(hash);
            return Ok(Vec::new());
        }
        if hash == self.bad_hash {
            return Err("rejected by scripted pool".to_string());
        }
        panic!("unexpected transaction {hash}");
    }

    fn have_transaction(&mut self, hash: &Hash) -> bool {
        self.have.contains(hash)
    }

    fn prune_stake_tx(&mut self, _required_stake_difficulty: i64, _height: i64) {}
    fn prune_expired_tx(&mut self, _height: i64) {}
}

/// A scripted mixing pool: the crafted pair request is rejected and
/// nothing is ever recent.  Messages are carried as their hashes.
#[derive(Default)]
struct ScriptedMixPool {
    reject: HashSet<Hash>,
}

impl SyncMixPool for ScriptedMixPool {
    type Msg = Hash;
    type Err = String;

    fn mix_hash(&mut self, msg: &Hash) -> Hash {
        *msg
    }

    fn accept_message(&mut self, msg: &Hash, _source: u64) -> Result<Vec<Hash>, String> {
        if self.reject.contains(msg) {
            return Err("rejected by scripted pool".to_string());
        }
        panic!("unexpected mix message {msg}");
    }

    fn recent_message(&mut self, _hash: &Hash) -> bool {
        false
    }

    fn remove_spent_prs(&mut self, _txs: &[MsgTx]) {}
    fn expire_messages_in_background(&mut self, _height: u32) {}
}

/// A stub chain for the standalone progress-guess battery manager.
struct StubChain;

impl SyncChain for StubChain {
    fn best_header(&mut self) -> (Hash, i64) {
        (Hash([0u8; 32]), 0)
    }
    fn header_by_hash(&mut self, _hash: &Hash) -> Option<BlockHeader> {
        None
    }
    fn block_locator_from_hash(&mut self, _hash: &Hash) -> Vec<Hash> {
        Vec::new()
    }
    fn put_next_needed_blocks(&mut self, _max_results: usize) -> Vec<Hash> {
        Vec::new()
    }
    fn best_snapshot(&mut self) -> BestSnapshot {
        BestSnapshot {
            hash: Hash([0u8; 32]),
            height: 0,
            next_stake_diff: 0,
        }
    }
    fn is_current(&mut self) -> bool {
        false
    }
    fn maybe_update_is_current(&mut self) {}
    fn chain_work(&mut self, _hash: &Hash) -> Option<dcroxide_uint256::Uint256> {
        None
    }
    fn have_header(&mut self, _hash: &Hash) -> bool {
        false
    }
    fn have_block(&mut self, _hash: &Hash) -> bool {
        false
    }
    fn process_block_header(&mut self, _header: &BlockHeader) -> Result<(), String> {
        Err("stub".to_string())
    }
    fn process_block(&mut self, _block: &MsgBlock) -> Result<i64, ProcessBlockFailure> {
        Err(ProcessBlockFailure {
            is_duplicate_block: false,
            message: "stub".to_string(),
        })
    }
}

/// The frozen per-peer facts.
struct PeerInfo {
    id: i32,
    inbound: bool,
    services: u64,
    pver: u32,
    last_block: i64,
}

/// The most recently observed state of a peer for probes issued after
/// the manager dropped it (dcrd's probes read the still-live peer
/// object).
#[derive(Clone, Default)]
struct PeerShadow {
    connected: bool,
    last_block: i64,
    consec: i64,
    orphan: String,
    best_ann: String,
}

fn config(
    params: &Params,
    chain: ChainAdapter,
) -> Config<ChainAdapter, ScriptedTxPool, ScriptedMixPool> {
    Config {
        chain,
        tx_mem_pool: ScriptedTxPool::default(),
        mix_pool: ScriptedMixPool::default(),
        min_known_chain_work: params.min_known_chain_work,
        net: params.net,
        target_time_per_block_secs: params.target_time_per_block_secs,
        no_mining_state_sync: false,
        max_outbound_peers: 8,
        max_orphan_txs: 100,
        recently_confirmed_txns: std::sync::Arc::new(std::sync::Mutex::new(apbf::new_filter(
            62500, 0.0000001,
        ))),
    }
}

#[test]
fn netsync_scenario_matches_dcrd() {
    let params = regnet_params();

    // First pass: gather the fixtures.
    let mut now = 0i64;
    let mut blocks: BTreeMap<i64, MsgBlock> = BTreeMap::new();
    let mut corrupt_block: Option<MsgBlock> = None;
    let mut peer_infos: HashMap<String, PeerInfo> = HashMap::new();
    let mut txs: HashMap<String, MsgTx> = HashMap::new();
    let mut hashes: HashMap<String, Hash> = HashMap::new();
    let mut mix_hash = Hash([0u8; 32]);
    for line in VECTORS.lines() {
        let f: Vec<&str> = line.split('|').collect();
        match f[0] {
            "now" => now = f[1].parse().unwrap(),
            "blk" => {
                let (block, _) = MsgBlock::from_bytes(&unhex(f[2])).unwrap();
                blocks.insert(f[1].parse().unwrap(), block);
            }
            "blkcorrupt" => {
                let (block, _) = MsgBlock::from_bytes(&unhex(f[2])).unwrap();
                corrupt_block = Some(block);
            }
            "peerinfo" => {
                peer_infos.insert(
                    f[1].to_string(),
                    PeerInfo {
                        id: f[2].parse().unwrap(),
                        inbound: f[3] == "true",
                        services: f[4].parse().unwrap(),
                        pver: f[5].parse().unwrap(),
                        last_block: f[6].parse().unwrap(),
                    },
                );
            }
            "tx" => {
                let (tx, _) = MsgTx::from_bytes(&unhex(f[2])).unwrap();
                txs.insert(f[1].to_string(), tx);
            }
            "hash" => {
                hashes.insert(f[1].to_string(), f[2].parse().unwrap());
            }
            "mix" => {
                mix_hash = f[2].parse().unwrap();
            }
            _ => {}
        }
    }
    let corrupt_block = corrupt_block.expect("corrupt block");
    let orphan_hash = txs["orphan"].tx_hash();
    let bad_hash = txs["bad"].tx_hash();
    let known_hash = blocks[&36].header.block_hash();

    // The manager over the real chain engine and scripted pools.
    let chain = ChainAdapter {
        chain: Chain::new(&params, Hash::ZERO, false),
        params: params.clone(),
        now,
    };
    let mut cfg = config(&params, chain);
    cfg.tx_mem_pool.orphan_hash = orphan_hash;
    cfg.tx_mem_pool.bad_hash = bad_hash;
    cfg.mix_pool.reject.insert(mix_hash);
    cfg.recently_confirmed_txns
        .lock()
        .expect("filter")
        .add(&hashes["confirmed"].0);
    let mut m = SyncManager::new(cfg);

    // Second pass: drive the scenario and compare every message and
    // probe.  Actions are grouped per peer within a step because dcrd
    // iterates its peer set in random map order while the per-peer
    // message streams are ordered.
    let mut step = 0u32;
    let mut step_msgs: BTreeMap<i32, Vec<String>> = BTreeMap::new();
    let mut shadows: HashMap<String, PeerShadow> = HashMap::new();
    let mut checked_msgs = 0usize;
    let mut checked_probes = 0usize;

    let record = |step_msgs: &mut BTreeMap<i32, Vec<String>>, actions: Vec<Action>| {
        for action in actions {
            match action {
                Action::QueueMessage { peer, message } => {
                    let payload = message.encode_payload(PROTOCOL_VERSION).unwrap();
                    let hex: String = payload.iter().map(|b| format!("{b:02x}")).collect();
                    let command = message.command().to_string();
                    step_msgs
                        .entry(peer)
                        .or_default()
                        .push(format!("{command}|{hex}"));
                }
                // Disconnects are verified via the connected probes and
                // the stall timer has no dcrd-observable counterpart.
                Action::Disconnect { .. }
                | Action::ResetHeaderSyncStallTimeout
                | Action::StopHeaderSyncStallTimeout => {}
            }
        }
    };

    let update_shadows = |m: &SyncManager<ChainAdapter, ScriptedTxPool, ScriptedMixPool>,
                          shadows: &mut HashMap<String, PeerShadow>,
                          peer_infos: &HashMap<String, PeerInfo>| {
        for (label, info) in peer_infos {
            if let Some(peer) = m.peer(info.id) {
                shadows.insert(
                    label.clone(),
                    PeerShadow {
                        connected: peer.connected(),
                        last_block: peer.last_block(),
                        consec: peer.num_consecutive_orphan_headers(),
                        orphan: peer
                            .announced_orphan_block()
                            .map_or("-".to_string(), |h| h.to_string()),
                        best_ann: peer
                            .best_announced_block()
                            .map_or("-".to_string(), |h| h.to_string()),
                    },
                );
            }
        }
    };

    for line in VECTORS.lines() {
        let f: Vec<&str> = line.split('|').collect();
        match f[0] {
            "step" => {
                step = f[1].parse().unwrap();
                let op = f[2];
                let label = f.get(3).copied().unwrap_or("");
                let peer_id = peer_infos.get(label).map(|i| i.id).unwrap_or(0);
                step_msgs.clear();
                let actions = match op {
                    "onpeerconnected" => {
                        let info = &peer_infos[label];
                        let peer = Peer::new(
                            info.id,
                            info.inbound,
                            ServiceFlag(info.services),
                            info.pver,
                            info.last_block,
                        );
                        m.on_peer_connected(peer)
                    }
                    "onpeerdisconnected" => m.on_peer_disconnected(peer_id),
                    "onheaders" => {
                        let first: i64 = f[4].parse().unwrap();
                        let last: i64 = f[5].parse().unwrap();
                        let headers = (first..=last).map(|h| blocks[&h].header).collect();
                        m.on_headers(peer_id, &MsgHeaders { headers })
                    }
                    "onblock" | "processblock" => {
                        let height: i64 = f[4].parse().unwrap();
                        let block = &blocks[&height];
                        if op == "processblock" {
                            let result = m.process_block(block);
                            // The result row is checked below.
                            let _ = result;
                            Vec::new()
                        } else {
                            m.on_block(peer_id, block)
                        }
                    }
                    "onblockcorrupt" => m.on_block(peer_id, &corrupt_block),
                    "oninv" => {
                        let (inv_type, hash) = match f[4] {
                            "blockunknown" => (InvType::BLOCK, hashes["unknownblock"]),
                            "blockknown" => (InvType::BLOCK, known_hash),
                            "txorphan" | "txorphanagain" => (InvType::TX, orphan_hash),
                            "txbad" | "txbadagain" | "txbadthird" | "txbadother" => {
                                (InvType::TX, bad_hash)
                            }
                            "txconfirmed" => (InvType::TX, hashes["confirmed"]),
                            "mixpr" => (InvType::MIX, mix_hash),
                            other => panic!("unknown inv tag {other}"),
                        };
                        m.on_inv(
                            peer_id,
                            &MsgInv {
                                inv_list: vec![InvVect { inv_type, hash }],
                            },
                        )
                    }
                    "ontx" => {
                        let tx = &txs[f[4]];
                        let accepted = m.on_tx(peer_id, tx);
                        // The accepted count row is checked below via
                        // txresult; stash it in the shadow-free way.
                        step_msgs
                            .entry(-1)
                            .or_default()
                            .push(format!("txresult|{}", accepted.len()));
                        Vec::new()
                    }
                    "onmixmsg" => {
                        let result = m.on_mix_msg(peer_id, &mix_hash);
                        step_msgs
                            .entry(-1)
                            .or_default()
                            .push(format!("mixresult|{}", result.is_err()));
                        Vec::new()
                    }
                    "onnotfound" => {
                        let (inv_type, hash) = match f[4] {
                            "vote" => (InvType::TX, hashes["vote"]),
                            "unknownblock" => (InvType::BLOCK, hashes["unknownblock"]),
                            other => panic!("unknown notfound tag {other}"),
                        };
                        m.on_not_found(
                            peer_id,
                            &MsgNotFound {
                                inv_list: vec![InvVect { inv_type, hash }],
                            },
                        );
                        Vec::new()
                    }
                    "requestfrompeer" => m.request_from_peer(
                        peer_id,
                        &[known_hash, hashes["unknownblock"]],
                        &[hashes["vote"]],
                        &[],
                    ),
                    "requestmixmsg" => {
                        let hash = match f[4] {
                            "unknown" | "unknownagain" => hashes["unknownmix"],
                            "rejected" => mix_hash,
                            other => panic!("unknown mix tag {other}"),
                        };
                        m.request_mix_msg_from_peer(peer_id, &hash)
                    }
                    other => panic!("unknown step op {other}"),
                };
                record(&mut step_msgs, actions);
                update_shadows(&m, &mut shadows, &peer_infos);
            }
            "msg" => {
                assert_eq!(f[1].parse::<u32>().unwrap(), step, "msg row out of step");
                let label = f[2];
                let want = format!("{}|{}", f[3], f[4]);
                let id = peer_infos[label].id;
                let queue = step_msgs.entry(id).or_default();
                assert!(
                    !queue.is_empty(),
                    "step {step}: expected {label} message {want} but none queued"
                );
                let got = queue.remove(0);
                assert_eq!(got, want, "step {step}: {label} message mismatch");
                checked_msgs += 1;
            }
            "txresult" => {
                let want = format!("txresult|{}", f[2]);
                let got = step_msgs.entry(-1).or_default().remove(0);
                assert_eq!(got, want, "step {step}: tx result");
            }
            "mixresult" => {
                let want = format!("mixresult|{}", f[2]);
                let got = step_msgs.entry(-1).or_default().remove(0);
                assert_eq!(got, want, "step {step}: mix result");
            }
            "processblockresult" => {
                // The duplicate submission fails through the local
                // path; re-run it directly to observe the error.
                let want_err = f[2] == "true";
                let height = 40;
                let result = m.process_block(&blocks[&height]);
                // Note the dump only submitted it once; a duplicate
                // stays a duplicate, so re-running is equivalent.
                assert_eq!(result.is_err(), want_err, "step {step}: processblock");
                if let Err(failure) = result {
                    assert!(failure.is_duplicate_block, "step {step}: duplicate kind");
                }
            }
            "probe" => {
                assert_eq!(f[1].parse::<u32>().unwrap(), step, "probe row out of step");
                checked_probes += 1;
                match f[2] {
                    "syncpeer" => {
                        assert_eq!(
                            i64::from(m.sync_peer_id()),
                            f[3].parse::<i64>().unwrap(),
                            "step {step}: sync peer"
                        );
                    }
                    "syncheight" => {
                        assert_eq!(
                            m.sync_height(),
                            f[3].parse::<i64>().unwrap(),
                            "step {step}: sync height"
                        );
                    }
                    "iscurrent" => {
                        assert_eq!(m.is_current(), f[3] == "true", "step {step}: is current");
                    }
                    "hdrsynced" => {
                        assert_eq!(
                            m.initial_header_sync_done(),
                            f[3] == "true",
                            "step {step}: headers synced"
                        );
                        assert_eq!(
                            m.initial_chain_sync_done(),
                            f[5] == "true",
                            "step {step}: chain sync done"
                        );
                    }
                    "reqblocks" | "reqtxns" | "reqmix" => {
                        let idx = match f[2] {
                            "reqtxns" => 0,
                            "reqblocks" => 1,
                            _ => 2,
                        };
                        let snap = &m.requested_snapshot()[idx];
                        let got: Vec<String> =
                            snap.iter().map(|(h, p)| format!("{h}:{p}")).collect();
                        let want: Vec<String> = if f[3].is_empty() {
                            Vec::new()
                        } else {
                            f[3].split(',').map(|s| s.to_string()).collect()
                        };
                        assert_eq!(got, want, "step {step}: {}", f[2]);
                    }
                    "peer" => {
                        let label = f[3];
                        let shadow = shadows.get(label).cloned().unwrap_or_default();
                        assert_eq!(
                            shadow.connected.to_string(),
                            f[5],
                            "step {step}: {label} connected"
                        );
                        assert_eq!(
                            shadow.last_block.to_string(),
                            f[7],
                            "step {step}: {label} last block"
                        );
                        assert_eq!(
                            shadow.consec.to_string(),
                            f[9],
                            "step {step}: {label} consecutive orphans"
                        );
                        assert_eq!(shadow.orphan, f[11], "step {step}: {label} orphan");
                        assert_eq!(
                            shadow.best_ann, f[13],
                            "step {step}: {label} best announced"
                        );
                    }
                    "bestheader" => {
                        let (hash, height) = m.chain_mut().best_header();
                        assert_eq!(hash.to_string(), f[3], "step {step}: best header hash");
                        assert_eq!(
                            height,
                            f[4].parse::<i64>().unwrap(),
                            "step {step}: best header height"
                        );
                    }
                    "rejtx" => {
                        let hash: Hash = f[3].parse().unwrap();
                        assert_eq!(
                            m.rejected_txns_contains(&hash),
                            f[4] == "true",
                            "step {step}: rejected tx filter"
                        );
                    }
                    "rejmix" => {
                        let hash: Hash = f[3].parse().unwrap();
                        assert_eq!(
                            m.rejected_mix_msgs_contains(&hash),
                            f[4] == "true",
                            "step {step}: rejected mix filter"
                        );
                    }
                    "pnnb8" | "pnnb512" => {
                        let max = if f[2] == "pnnb8" { 8 } else { 512 };
                        let got: Vec<String> = m
                            .chain_mut()
                            .put_next_needed_blocks(max)
                            .iter()
                            .map(|h| h.to_string())
                            .collect();
                        let want: Vec<String> = if f[3].is_empty() {
                            Vec::new()
                        } else {
                            f[3].split(',').map(|s| s.to_string()).collect()
                        };
                        assert_eq!(got, want, "step {step}: {}", f[2]);
                    }
                    other => panic!("unknown probe {other}"),
                }
            }
            "prog" if f[1] == "regnet" => {
                let prog_now: i64 = f[2].parse().unwrap();
                let want = u64::from_str_radix(f[3], 16).unwrap();
                let got = m.header_sync_progress(prog_now);
                assert_eq!(got.to_bits(), want, "regnet header sync progress");
            }
            _ => {}
        }
    }

    // No unconsumed queued messages after the final step.
    for (peer, queue) in &step_msgs {
        assert!(
            queue.is_empty() || *peer == -1,
            "step {step}: unconsumed messages for peer {peer}: {queue:?}"
        );
    }

    assert_eq!(checked_msgs, 25, "unexpected message row count");
    assert!(checked_probes > 900, "unexpected probe row count");
}

#[test]
fn header_sync_progress_guess_matches_dcrd() {
    let params = mainnet_params();
    let chain = StubChain;
    let cfg = Config {
        chain,
        tx_mem_pool: ScriptedTxPool::default(),
        mix_pool: ScriptedMixPool::default(),
        min_known_chain_work: params.min_known_chain_work,
        net: params.net,
        target_time_per_block_secs: params.target_time_per_block_secs,
        no_mining_state_sync: false,
        max_outbound_peers: 8,
        max_orphan_txs: 100,
        recently_confirmed_txns: std::sync::Arc::new(std::sync::Mutex::new(apbf::new_filter(
            62500, 0.0000001,
        ))),
    };
    let m = SyncManager::new(cfg);

    let mut rows = 0;
    for line in VECTORS.lines() {
        let f: Vec<&str> = line.split('|').collect();
        if f[0] != "prog" || f[1] != "guess" {
            continue;
        }
        rows += 1;
        let height: u32 = f[2].parse().unwrap();
        let ts: i64 = f[3].parse().unwrap();
        let now: i64 = f[4].parse().unwrap();
        let want = u64::from_str_radix(f[5], 16).unwrap();
        let mut header = empty_header();
        header.height = height;
        header.timestamp = ts as u32;
        let got = m.guess_header_sync_progress(&header, now);
        assert_eq!(got.to_bits(), want, "guess {height} {ts}");
    }
    assert_eq!(rows, 4, "unexpected guess row count");
}

/// The header sync stall timeout disconnects the sync peer (the body
/// of dcrd's stallHandler timer case, which the dump cannot trigger
/// deterministically).
#[test]
fn stall_timeout_disconnects_sync_peer() {
    let params = regnet_params();
    let chain = ChainAdapter {
        chain: Chain::new(&params, Hash::ZERO, false),
        params: params.clone(),
        now: 0,
    };
    let mut m = SyncManager::new(config(&params, chain));

    // No sync peer: nothing happens.
    assert!(m.on_header_sync_stall_timeout().is_empty());

    // With a sync candidate connected during the header sync, the
    // timeout disconnects it.
    let actions = m.on_peer_connected(Peer::new(7, false, ServiceFlag(1), PROTOCOL_VERSION, 50));
    assert!(
        actions
            .iter()
            .any(|a| matches!(a, Action::QueueMessage { peer: 7, .. })),
        "expected an initial getheaders"
    );
    assert_eq!(m.sync_peer_id(), 7);
    let actions = m.on_header_sync_stall_timeout();
    assert_eq!(actions, vec![Action::Disconnect { peer: 7 }]);
    assert!(!m.peer(7).unwrap().connected());
}
